SELECT C.FUNCAO FROM SERVIDOR_PROJ SP JOIN PROJ PJ ON PJ.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE JOIN CARGO C ON C.FK_SIAPE = S.PK_SIAPE WHERE LOWER(C.SIGLA_CAMPUS) = LOWER('itu') AND LOWER(PJ.AREA_CONHECIMENTO) LIKE LOWER('educa%') AND LOWER(S.GENERO) = LOWER('masculino') AND SP.DATA_SAIDA >= DATE('now', '-5 years') AND SP.DATA_ENTRADA <= DATE('now') GROUP BY C.FUNCAO HAVING COUNT(DISTINCT SP.PK) = 3